// src/TicketHistory.jsx
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const apiBase = "https://prasa-app-yde3.onrender.com";
const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function TicketHistory({ employee }) {
  const navigate = useNavigate();
  const [ticketExpenses, setTicketExpenses] = useState([]);
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");

  useEffect(() => {
    if (employee?.empld) fetchData();
  }, [employee]);

 const fetchData = async () => {
  try {
    const empId = employee.empId || employee.empld;

    const res = await fetch(
      `${apiBase}/ticket-expenses?empId=${encodeURIComponent(empId)}`
    );

    const data = await res.json();
    console.log("TICKET RESPONSE FROM BACKEND:", data);

    setTicketExpenses(Array.isArray(data) ? data : []);
  } catch {
    setTicketExpenses([]);
  }
};


  const filtered = ticketExpenses.filter((t) => {
    const d = t.ticket_date?.split?.("T")?.[0] || t.ticket_date;
    if (startDate && d < startDate) return false;
    if (endDate && d > endDate) return false;
    return true;
  });

  const handleDownloadPDF = () => window.print();

  const deleteTicket = async (id) => {
    if (!window.confirm("Delete ticket?")) return;
    try {
      const res = await fetch(`${apiBase}/ticket-expenses/${id}`, {
        method: "DELETE",
      });
      const data = await res.json();
      if (!data.success) return alert(data.message);
      setTicketExpenses((prev) => prev.filter((x) => x.id !== id));
    } catch {
      alert("Delete error");
    }
  };

  const editTicket = async (row) => {
    const newDate =
      window.prompt("Date:", row.ticket_date?.split?.("T")?.[0]) ||
      row.ticket_date;
    const newPurpose = window.prompt("Purpose:", row.purpose) || row.purpose;
    const newAssign =
      window.prompt("Assigned To:", row.assigned_to) || row.assigned_to;
    const newAmount = window.prompt("Amount:", row.amount) || row.amount;

    try {
      const res = await fetch(`${apiBase}/ticket-expenses/${row.id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ticket_date: newDate,
          purpose: newPurpose,
          assigned_to: newAssign,
          amount: newAmount,
        }),
      });

      const data = await res.json();
      if (!data.success) return alert("Update failed");

      setTicketExpenses((prev) =>
        prev.map((t) =>
          t.id === row.id
            ? {
                ...t,
                ticket_date: newDate,
                purpose: newPurpose,
                assigned_to: newAssign,
                amount: newAmount,
              }
            : t
        )
      );
    } catch {
      alert("Update error");
    }
  };

  if (!employee)
    return <div style={centerScreen}>Please login again.</div>;

  return (
    <div style={outer}>
      <div style={card}>
        <div style={headerRow}>
          <button style={backBtn} onClick={() => navigate("/history")}>
            ⬅ Back
          </button>
          <h2 style={title}>Ticket Expense History</h2>
        </div>

        <p style={empInfo}>
          {employee.name} • {employee.empld}
        </p>

        {/* FILTERS */}
        <div style={filterBar}>
          <div style={filterBlock}>
            <span>From</span>
            <input
              type="date"
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              style={filterInput}
            />
          </div>
          <div style={filterBlock}>
            <span>To</span>
            <input
              type="date"
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
              style={filterInput}
            />
          </div>
          <button
            onClick={() => {
              setStartDate("");
              setEndDate("");
            }}
            style={clearBtn}
          >
            Clear
          </button>
        </div>

        {/* TABLE */}
        <table style={table}>
          <thead>
            <tr>
              <th>Date</th>
              <th>Purpose</th>
              <th>Assigned To</th>
              <th>Amount</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody>
            {filtered.map((t) => (
              <tr key={t.id}>
                <td>{t.ticket_date?.split?.("T")?.[0]}</td>
                <td>{t.purpose}</td>
                <td>{t.assigned_to}</td>
                <td>₹{t.amount}</td>
                <td>
                  <button style={editBtn} onClick={() => editTicket(t)}>
                    Edit
                  </button>
                  <button style={delBtn} onClick={() => deleteTicket(t.id)}>
                    Delete
                  </button>
                </td>
              </tr>
            ))}

            {filtered.length === 0 && (
              <tr>
                <td colSpan="5" style={noData}>
                  No ticket records found.
                </td>
              </tr>
            )}
          </tbody>
        </table>

        {/* PDF BUTTON */}
        <div style={pdfRow}>
          <button style={pdfBtn} onClick={handleDownloadPDF}>
            Download PDF
          </button>
        </div>
      </div>
    </div>
  );
}

// ---------- STYLES ----------
const outer = {
  minHeight: "100vh",
  background: lightGreen,
  padding: 20,
  fontFamily: "Segoe UI",
};

const centerScreen = {
  ...outer,
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
};

const card = {
  maxWidth: 950,
  margin: "0 auto",
  background: "#fff",
  padding: 20,
  borderRadius: 16,
  boxShadow: "0 6px 20px rgba(0,0,0,0.12)",
};

const headerRow = { display: "flex", alignItems: "center", gap: 10 };

const backBtn = {
  background: "none",
  border: "none",
  color: green,
  fontSize: 16,
  cursor: "pointer",
};

const title = { color: green, margin: 0 };
const empInfo = { fontSize: 13, marginTop: 6 };

const filterBar = {
  display: "flex",
  flexWrap: "wrap",
  gap: 10,
  padding: 10,
  margin: "14px 0",
  background: "#f9fff9",
  borderRadius: 10,
  border: "1px solid #eaf8f0",
};

const filterBlock = { display: "flex", flexDirection: "column", fontSize: 12 };

const filterInput = {
  padding: 5,
  borderRadius: 6,
  border: "1px solid #ccc",
};

const clearBtn = {
  padding: "5px 12px",
  borderRadius: 8,
  border: "1px solid #ccc",
  background: "#fff",
  cursor: "pointer",
};

const table = {
  width: "100%",
  borderCollapse: "collapse",
  fontSize: 13,
};

const editBtn = {
  padding: "3px 8px",
  marginRight: 6,
  border: `1px solid ${green}`,
  color: green,
  borderRadius: 6,
  background: "#fff",
  cursor: "pointer",
};

const delBtn = {
  padding: "3px 8px",
  borderRadius: 6,
  border: "1px solid #c62828",
  background: "#fff",
  color: "#c62828",
  cursor: "pointer",
};

const pdfRow = {
  display: "flex",
  justifyContent: "flex-start",
  marginTop: 20,
};

const pdfBtn = {
  padding: "8px 14px",
  borderRadius: 20,
  border: "none",
  background: green,
  color: "#fff",
  cursor: "pointer",
};

const noData = {
  padding: 10,
  textAlign: "center",
};
